// 接口定义：
void Buffer_Init(RingBuffer *rb);
bool Buffer_IsFull(RingBuffer *rb);

/* STM32 HAL DMA 循环缓冲区配置示例 */
#define BUFFER_SIZE 1024
uint8_t rx_buffer[BUFFER_SIZE];
volatile uint16_t head = 0;

void HAL_ADC_ConvHalfCpltCallback(ADC_HandleTypeDef* hadc) {
    /* DMA 已完成前半部分传输 */
    Process_Data(&rx_buffer[0], BUFFER_SIZE / 2);
}

void HAL_ADC_ConvCpltCallback(ADC_HandleTypeDef* hadc) {
    /* DMA 已完成整个缓冲区传输 */
    Process_Data(&rx_buffer[BUFFER_SIZE / 2], BUFFER_SIZE / 2);
}

/* 初始化配置 */
void DMA_Init(void) {
    // 必须确保中断优先级设置合适，防止被高优先级任务阻塞
    HAL_NVIC_SetPriority(DMA2_Stream0_IRQn, 0, 0);
    HAL_NVIC_EnableIRQ(DMA2_Stream0_IRQn);

    // 启动循环模式
    HAL_ADC_Start_DMA(&hadc1, (uint32_t*)rx_buffer, BUFFER_SIZE);
}

// Before:

// 坏味道：直接操作全局数组，耦合度高，不安全
uint8_t buffer[1024];
void ADC_Handler() { 
    if(buffer[10] > 100) { do_something(); } 
}


// After:

// 改进：使用接口封装与私有化数据
typedef struct { uint8_t *ptr; size_t size; } RingBuffer;
static RingBuffer g_adc_ring = {rx_buffer, 1024};

void Process_Adc_Data(RingBuffer *rb) {
    if(rb->ptr[10] > 100) { do_something(); }
}
